// Get Funds from users
// Withdraw funds
// Set a minimum funding value in USD


// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

// CHAINLINK AGGREGATOR V3 INTERFACE
import "./AggregatorV3Interface.sol";



contract FundMe {

    uint256 public minimumUSD = 50;

    function fund() public payable {
        // set a minimum funding value in USD
        // How do we send ETH to this contract?

        require(msg.value >= minimumUSD, "Minimum required fund not met");
    }

    function getPrice() public {
        // ABI

        // ETH/USD price feed contract address from chain link latest price feed
        // address 0x5f4eC3Df9cbd43714FE2740f5E3616155c5b8419
        
    }

    function getVersion() public view returns(uint256) {
        AggregatorV3Interface priceFeed = AggregatorV3Interface(0x5f4eC3Df9cbd43714FE2740f5E3616155c5b8419);
        return priceFeed.version();
    }

    function getConversionRate() public {

    }

    // function withdraw() public {

    // }

}

contracts/AggregatorV3Interface.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface AggregatorV3Interface {
  function decimals() external view returns (uint8);
  function description() external view returns (string memory);
  function version() external view returns (uint256);

  function getRoundData(uint80 _roundId)
    external
    view
    returns (
      uint80 roundId,
      int256 answer,
      uint256 startedAt,
      uint256 updatedAt,
      uint80 answeredInRound
    );

  function latestRoundData()
    external
    view
    returns (
      uint80 roundId,
      int256 answer,
      uint256 startedAt,
      uint256 updatedAt,
      uint80 answeredInRound
    );
}

